17: package org.apache.kafka.common.security.scram.internals;
18: 
19: import org.apache.kafka.common.errors.AuthenticationException;
20: import org.apache.kafka.common.errors.IllegalSaslStateException;
21: import org.apache.kafka.common.errors.SaslAuthenticationException;
