35: /**
36:  * A Kafka connection either existing on a client (which could be a broker in an
37:  * inter-broker scenario) and representing the channel to a remote broker or the
38:  * reverse (existing on a broker and representing the channel to a remote
39:  * client, which could be a broker in an inter-broker scenario).
40:  * <p>
41:  * Each instance has the following:
42:  * <ul>
43:  * <li>a unique ID identifying it in the {@code KafkaClient} instance via which
44:  * the connection was made on the client-side or in the instance where it was
45:  * accepted on the server-side</li>
46:  * <li>a reference to the underlying {@link TransportLayer} to allow reading and
47:  * writing</li>
48:  * <li>an {@link Authenticator} that performs the authentication (or
49:  * re-authentication, if that feature is enabled and it applies to this
50:  * connection) by reading and writing directly from/to the same
51:  * {@link TransportLayer}.</li>
52:  * <li>a {@link MemoryPool} into which responses are read (typically the JVM
53:  * heap for clients, though smaller pools can be used for brokers and for
54:  * testing out-of-memory scenarios)</li>
55:  * <li>a {@link NetworkReceive} representing the current incomplete/in-progress
56:  * request (from the server-side perspective) or response (from the client-side
57:  * perspective) being read, if applicable; or a non-null value that has had no
58:  * data read into it yet or a null value if there is no in-progress
59:  * request/response (either could be the case)</li>
60:  * <li>a {@link Send} representing the current request (from the client-side
61:  * perspective) or response (from the server-side perspective) that is either
62:  * waiting to be sent or partially sent, if applicable, or null</li>
63:  * <li>a {@link ChannelMuteState} to document if the channel has been muted due
64:  * to memory pressure or other reasons</li>
65:  * </ul>
66:  */
67: public class KafkaChannel implements AutoCloseable {
68:     private static final long MIN_REAUTH_INTERVAL_ONE_SECOND_NANOS = 1000 * 1000 * 1000;
69: 
70:     /**
71:      * Mute States for KafkaChannel:
72:      * <ul>
73:      *   <li> NOT_MUTED: Channel is not muted. This is the default state. </li>
74:      *   <li> MUTED: Channel is muted. Channel must be in this state to be unmuted. </li>
75:      *   <li> MUTED_AND_RESPONSE_PENDING: (SocketServer only) Channel is muted and SocketServer has not sent a response
76:      *                                    back to the client yet (acks != 0) or is currently waiting to receive a
77:      *                                    response from the API layer (acks == 0). </li>
78:      *   <li> MUTED_AND_THROTTLED: (SocketServer only) Channel is muted and throttling is in progress due to quota
79:      *                             violation. </li>
80:      *   <li> MUTED_AND_THROTTLED_AND_RESPONSE_PENDING: (SocketServer only) Channel is muted, throttling is in progress,
81:      *                                                  and a response is currently pending. </li>
82:      * </ul>
83:      */
84:     public enum ChannelMuteState {
85:         NOT_MUTED,
86:         MUTED,
87:         MUTED_AND_RESPONSE_PENDING,
88:         MUTED_AND_THROTTLED,
89:         MUTED_AND_THROTTLED_AND_RESPONSE_PENDING
90:     }
91: 
92:     /** Socket server events that will change the mute state:
93:      * <ul>
94:      *   <li> REQUEST_RECEIVED: A request has been received from the client. </li>
95:      *   <li> RESPONSE_SENT: A response has been sent out to the client (ack != 0) or SocketServer has heard back from
96:      *                       the API layer (acks = 0) </li>
97:      *   <li> THROTTLE_STARTED: Throttling started due to quota violation. </li>
98:      *   <li> THROTTLE_ENDED: Throttling ended. </li>
99:      * </ul>
100:      *
101:      * Valid transitions on each event are:
102:      * <ul>
103:      *   <li> REQUEST_RECEIVED: MUTED => MUTED_AND_RESPONSE_PENDING </li>
104:      *   <li> RESPONSE_SENT:    MUTED_AND_RESPONSE_PENDING => MUTED, MUTED_AND_THROTTLED_AND_RESPONSE_PENDING => MUTED_AND_THROTTLED </li>
105:      *   <li> THROTTLE_STARTED: MUTED_AND_RESPONSE_PENDING => MUTED_AND_THROTTLED_AND_RESPONSE_PENDING </li>
106:      *   <li> THROTTLE_ENDED:   MUTED_AND_THROTTLED => MUTED, MUTED_AND_THROTTLED_AND_RESPONSE_PENDING => MUTED_AND_RESPONSE_PENDING </li>
107:      * </ul>
108:      */
109:     public enum ChannelMuteEvent {
110:         REQUEST_RECEIVED,
111:         RESPONSE_SENT,
112:         THROTTLE_STARTED,
113:         THROTTLE_ENDED
114:     }
