116:     private final String id;
117:     private final TransportLayer transportLayer;
118:     private final Supplier<Authenticator> authenticatorCreator;
119:     private Authenticator authenticator;
120:     // Tracks accumulated network thread time. This is updated on the network thread.
121:     // The values are read and reset after each response is sent.
122:     private long networkThreadTimeNanos;
123:     private final int maxReceiveSize;
124:     private final MemoryPool memoryPool;
125:     private final ChannelMetadataRegistry metadataRegistry;
126:     private NetworkReceive receive;
127:     private NetworkSend send;
128:     // Track connection and mute state of channels to enable outstanding requests on channels to be
129:     // processed after the channel is disconnected.
130:     private boolean disconnected;
131:     private ChannelMuteState muteState;
132:     private ChannelState state;
133:     private SocketAddress remoteAddress;
134:     private int successfulAuthentications;
135:     private boolean midWrite;
136:     private long lastReauthenticationStartNanos;
