138:     public KafkaChannel(String id, TransportLayer transportLayer, Supplier<Authenticator> authenticatorCreator,
139:                         int maxReceiveSize, MemoryPool memoryPool, ChannelMetadataRegistry metadataRegistry) {
140:         this.id = id;
141:         this.transportLayer = transportLayer;
142:         this.authenticatorCreator = authenticatorCreator;
143:         this.authenticator = authenticatorCreator.get();
144:         this.networkThreadTimeNanos = 0L;
145:         this.maxReceiveSize = maxReceiveSize;
146:         this.memoryPool = memoryPool;
147:         this.metadataRegistry = metadataRegistry;
148:         this.disconnected = false;
149:         this.muteState = ChannelMuteState.NOT_MUTED;
150:         this.state = ChannelState.NOT_CONNECTED;
151:     }
152: 
153:     public void close() throws IOException {
154:         this.disconnected = true;
155:         Utils.closeAll(transportLayer, authenticator, receive, metadataRegistry);
156:     }
157: 
158:     /**
159:      * Returns the principal returned by `authenticator.principal()`.
160:      */
161:     public KafkaPrincipal principal() {
162:         return authenticator.principal();
163:     }
164: 
165:     public Optional<KafkaPrincipalSerde> principalSerde() {
166:         return authenticator.principalSerde();
167:     }
168: 
169:     /**
170:      * Does handshake of transportLayer and authentication using configured authenticator.
171:      * For SSL with client authentication enabled, {@link TransportLayer#handshake()} performs
172:      * authentication. For SASL, authentication is performed by {@link Authenticator#authenticate()}.
173:      */
174:     public void prepare() throws AuthenticationException, IOException {
175:         boolean authenticating = false;
176:         try {
177:             if (!transportLayer.ready())
178:                 transportLayer.handshake();
179:             if (transportLayer.ready() && !authenticator.complete()) {
180:                 authenticating = true;
181:                 authenticator.authenticate();
182:             }
183:         } catch (AuthenticationException e) {
184:             // Clients are notified of authentication exceptions to enable operations to be terminated
185:             // without retries. Other errors are handled as network exceptions in Selector.
186:             String remoteDesc = remoteAddress != null ? remoteAddress.toString() : null;
187:             state = new ChannelState(ChannelState.State.AUTHENTICATION_FAILED, e, remoteDesc);
188:             if (authenticating) {
189:                 delayCloseOnAuthenticationFailure();
190:                 throw new DelayedResponseAuthenticationException(e);
191:             }
192:             throw e;
193:         }
194:         if (ready()) {
195:             ++successfulAuthentications;
196:             state = ChannelState.READY;
197:         }
198:     }
199: 
200:     public void disconnect() {
201:         disconnected = true;
202:         if (state == ChannelState.NOT_CONNECTED && remoteAddress != null) {
203:             //if we captured the remote address we can provide more information
204:             state = new ChannelState(ChannelState.State.NOT_CONNECTED, remoteAddress.toString());
205:         }
206:         transportLayer.disconnect();
207:     }
208: 
209:     public void state(ChannelState state) {
210:         this.state = state;
211:     }
212: 
213:     public ChannelState state() {
214:         return this.state;
215:     }
