217:     public boolean finishConnect() throws IOException {
218:         //we need to grab remoteAddr before finishConnect() is called otherwise
219:         //it becomes inaccessible if the connection was refused.
220:         SocketChannel socketChannel = transportLayer.socketChannel();
221:         if (socketChannel != null) {
