48:     private ScramFormatter formatter;
49:     private ScramSaslServer saslServer;
50: 
51:     @BeforeEach
52:     public void setUp() throws Exception {
53:         ScramMechanism mechanism = ScramMechanism.SCRAM_SHA_256;
54:         formatter  = new ScramFormatter(mechanism);
55:         CredentialCache.Cache<ScramCredential> credentialCache = new CredentialCache().createCache(mechanism.mechanismName(), ScramCredential.class);
56:         credentialCache.put(USER_A, formatter.generateCredential("passwordA", 4096));
57:         credentialCache.put(USER_B, formatter.generateCredential("passwordB", 4096));
58:         ScramServerCallbackHandler callbackHandler = new ScramServerCallbackHandler(credentialCache, new DelegationTokenCache(ScramMechanism.mechanismNames()));
59:         saslServer = new ScramSaslServer(mechanism, new HashMap<>(), callbackHandler);
60:     }
61: 
62:     @Test
63:     public void noAuthorizationIdSpecified() throws Exception {
64:         byte[] nextChallenge = saslServer.evaluateResponse(clientFirstMessage(USER_A, null));
65:         assertTrue(nextChallenge.length > 0, "Next challenge is empty");
66:     }
67: 
68:     @Test
69:     public void authorizationIdEqualsAuthenticationId() throws Exception {
70:         byte[] nextChallenge = saslServer.evaluateResponse(clientFirstMessage(USER_A, USER_A));
71:         assertTrue(nextChallenge.length > 0, "Next challenge is empty");
72:     }
