28: import java.security.MessageDigest;
29: import java.security.NoSuchAlgorithmException;
30: import java.security.SecureRandom;
31: import java.util.regex.Matcher;
32: import java.util.regex.Pattern;
33: 
34: import javax.crypto.Mac;
35: import javax.crypto.spec.SecretKeySpec;
36: 
37: /**
38:  * Scram message salt and hash functions defined in <a href="https://tools.ietf.org/html/rfc5802">RFC 5802</a>.
39:  */
40: public class ScramFormatter {
41: 
42:     private static final Pattern EQUAL = Pattern.compile("=", Pattern.LITERAL);
43:     private static final Pattern COMMA = Pattern.compile(",", Pattern.LITERAL);
44:     private static final Pattern EQUAL_TWO_C = Pattern.compile("=2C", Pattern.LITERAL);
45:     private static final Pattern EQUAL_THREE_D = Pattern.compile("=3D", Pattern.LITERAL);
46: 
47:     private final MessageDigest messageDigest;
48:     private final Mac mac;
49:     private final SecureRandom random;
50: 
51:     public ScramFormatter(ScramMechanism mechanism) throws NoSuchAlgorithmException {
52:         this.messageDigest = MessageDigest.getInstance(mechanism.hashAlgorithm());
53:         this.mac = Mac.getInstance(mechanism.macAlgorithm());
54:         this.random = new SecureRandom();
55:     }
56: 
57:     public byte[] hmac(byte[] key, byte[] bytes) throws InvalidKeyException {
58:         mac.init(new SecretKeySpec(key, mac.getAlgorithm()));
59:         return mac.doFinal(bytes);
60:     }
61: 
62:     public byte[] hash(byte[] str) {
63:         return messageDigest.digest(str);
64:     }
65: 
66:     public static byte[] xor(byte[] first, byte[] second) {
67:         if (first.length != second.length)
68:             throw new IllegalArgumentException("Argument arrays must be of the same length");
69:         byte[] result = new byte[first.length];
70:         for (int i = 0; i < result.length; i++)
71:             result[i] = (byte) (first[i] ^ second[i]);
72:         return result;
73:     }
74: 
75:     public byte[] hi(byte[] str, byte[] salt, int iterations) throws InvalidKeyException {
76:         mac.init(new SecretKeySpec(str, mac.getAlgorithm()));
77:         mac.update(salt);
78:         byte[] u1 = mac.doFinal(new byte[]{0, 0, 0, 1});
79:         byte[] prev = u1;
80:         byte[] result = u1;
81:         for (int i = 2; i <= iterations; i++) {
82:             byte[] ui = hmac(str, prev);
83:             result = xor(result, ui);
84:             prev = ui;
85:         }
86:         return result;
87:     }
88: 
89:     public static byte[] normalize(String str) {
90:         return toBytes(str);
91:     }
92: 
93:     public byte[] saltedPassword(String password, byte[] salt, int iterations) throws InvalidKeyException {
94:         return hi(normalize(password), salt, iterations);
95:     }
96: 
97:     public byte[] clientKey(byte[] saltedPassword) throws InvalidKeyException {
98:         return hmac(saltedPassword, toBytes("Client Key"));
99:     }
100: 
101:     public byte[] storedKey(byte[] clientKey) {
102:         return hash(clientKey);
103:     }
104: 
105:     public static String saslName(String username) {
106:         String replace1 = EQUAL.matcher(username).replaceAll(Matcher.quoteReplacement("=3D"));
107:         return COMMA.matcher(replace1).replaceAll(Matcher.quoteReplacement("=2C"));
108:     }
109: 
110:     public static String username(String saslName) {
111:         String username = EQUAL_TWO_C.matcher(saslName).replaceAll(Matcher.quoteReplacement(","));
112:         if (EQUAL_THREE_D.matcher(username).replaceAll(Matcher.quoteReplacement("")).indexOf('=') >= 0) {
113:             throw new IllegalArgumentException("Invalid username: " + saslName);
114:         }
115:         return EQUAL_THREE_D.matcher(username).replaceAll(Matcher.quoteReplacement("="));
116:     }
117: 
118:     public static String authMessage(String clientFirstMessageBare, String serverFirstMessage, String clientFinalMessageWithoutProof) {
119:         return clientFirstMessageBare + "," + serverFirstMessage + "," + clientFinalMessageWithoutProof;
120:     }
121: 
122:     public byte[] clientSignature(byte[] storedKey, ClientFirstMessage clientFirstMessage, ServerFirstMessage serverFirstMessage, ClientFinalMessage clientFinalMessage) throws InvalidKeyException {
123:         byte[] authMessage = authMessage(clientFirstMessage, serverFirstMessage, clientFinalMessage);
124:         return hmac(storedKey, authMessage);
125:     }
126: 
127:     public byte[] clientProof(byte[] saltedPassword, ClientFirstMessage clientFirstMessage, ServerFirstMessage serverFirstMessage, ClientFinalMessage clientFinalMessage) throws InvalidKeyException {
128:         byte[] clientKey = clientKey(saltedPassword);
129:         byte[] storedKey = hash(clientKey);
130:         byte[] clientSignature = hmac(storedKey, authMessage(clientFirstMessage, serverFirstMessage, clientFinalMessage));
131:         return xor(clientKey, clientSignature);
132:     }
133: 
134:     private byte[] authMessage(ClientFirstMessage clientFirstMessage, ServerFirstMessage serverFirstMessage, ClientFinalMessage clientFinalMessage) {
135:         return toBytes(authMessage(clientFirstMessage.clientFirstMessageBare(),
136:                 serverFirstMessage.toMessage(),
137:                 clientFinalMessage.clientFinalMessageWithoutProof()));
138:     }
139: 
140:     public byte[] storedKey(byte[] clientSignature, byte[] clientProof) {
141:         return hash(xor(clientSignature, clientProof));
142:     }
143: 
144:     public byte[] serverKey(byte[] saltedPassword) throws InvalidKeyException {
145:         return hmac(saltedPassword, toBytes("Server Key"));
146:     }
147: 
148:     public byte[] serverSignature(byte[] serverKey, ClientFirstMessage clientFirstMessage, ServerFirstMessage serverFirstMessage, ClientFinalMessage clientFinalMessage) throws InvalidKeyException {
149:         byte[] authMessage = authMessage(clientFirstMessage, serverFirstMessage, clientFinalMessage);
150:         return hmac(serverKey, authMessage);
151:     }
152: 
153:     public String secureRandomString() {
154:         return secureRandomString(random);
155:     }
156: 
157:     public static String secureRandomString(SecureRandom random) {
158:         return new BigInteger(130, random).toString(Character.MAX_RADIX);
159:     }
160: 
161:     public byte[] secureRandomBytes() {
162:         return secureRandomBytes(random);
163:     }
164: 
165:     public static byte[] secureRandomBytes(SecureRandom random) {
166:         return toBytes(secureRandomString(random));
167:     }
168: 
169:     public static byte[] toBytes(String str) {
170:         return str.getBytes(StandardCharsets.UTF_8);
171:     }
172: 
173:     public ScramCredential generateCredential(String password, int iterations) {
174:         try {
175:             byte[] salt = secureRandomBytes();
176:             byte[] saltedPassword = saltedPassword(password, salt, iterations);
177:             return generateCredential(salt, saltedPassword, iterations);
178:         } catch (InvalidKeyException e) {
179:             throw new KafkaException("Could not create credential", e);
180:         }
181:     }
182: 
183:     public ScramCredential generateCredential(byte[] salt, byte[] saltedPassword, int iterations) {
184:         try {
185:             byte[] clientKey = clientKey(saltedPassword);
186:             byte[] storedKey = storedKey(clientKey);
187:             byte[] serverKey = serverKey(saltedPassword);
188:             return new ScramCredential(salt, storedKey, serverKey, iterations);
189:         } catch (InvalidKeyException e) {
190:             throw new KafkaException("Could not create credential", e);
191:         }
192:     }
